// FreeLang v4 OPSec Advanced Test Suite
// 고급 테스트 케이스

module OPSecAdvancedTests

// Test 1: 정책 강제 및 접근 제어
test "PolicyEnforcer: RBAC 규칙 검증" {
  let enforcer = PolicyEnforcer::new()

  // 규칙 설정
  enforcer
    .rule("admin", ["read", "write", "delete"], Resource::All)
    .rule("user", ["read"], Resource::Own)
    .rule("guest", ["read"], Resource::Public)

  // Admin 테스트
  let admin = User { id: "admin1", role: "admin" }
  assert!(enforcer.enforce(admin, "delete", "/data/sensitive").unwrap())

  // User 테스트
  let user = User { id: "user1", role: "user" }
  assert!(enforcer.enforce(user, "read", "/data/own").unwrap())
  assert!(!enforcer.enforce(user, "write", "/data/other").unwrap())

  // Guest 테스트
  let guest = User { id: "guest1", role: "guest" }
  assert!(enforcer.enforce(guest, "read", "/data/public").unwrap())
  assert!(!enforcer.enforce(guest, "write", "/data/public").unwrap())
}

// Test 2: 동적 정책 평가
test "PolicyEnforcer: 동적 정책 조건" {
  let enforcer = PolicyEnforcer::new()

  // 시간 기반 정책
  let now = get_current_hour()
  if now >= 9 && now <= 17 {
    enforcer.rule("employee", ["access_building"], Resource::All)
  } else {
    enforcer.rule("employee", ["request_access"], Resource::All)
  }

  let employee = User { id: "emp1", role: "employee" }
  // 업무 시간에는 접근 가능
  if now >= 9 && now <= 17 {
    assert!(enforcer.enforce(employee, "access_building", "/office").unwrap())
  }
}

// Test 3: 감사 로깅
test "AuditLogger: 이벤트 기록 및 암호화" {
  let audit = AuditLogger::new()
    .with_encryption("my-secret-key-32-chars-long-!!!")
    .with_retention(days: 90)

  // 정상 접근 로깅
  let event_id = audit.log(
    event_type: "access_granted",
    user: "user@example.com",
    resource: "/api/users",
    timestamp: now(),
    details: { action: "read", status: "success" }
  ).unwrap()

  assert!(event_id.len() > 0)

  // 접근 거부 로깅
  let deny_event = audit.log(
    event_type: "access_denied",
    user: "attacker@example.com",
    resource: "/admin/settings",
    timestamp: now(),
    details: { reason: "insufficient_permissions", ip: "192.168.1.100" }
  ).unwrap()

  assert!(deny_event.len() > 0)
}

// Test 4: 감사 로그 조회
test "AuditLogger: 로그 필터링 및 조회" {
  let audit = AuditLogger::new()
    .with_encryption("test-key-32-chars-long!!!!!")
    .with_retention(days: 90)

  // 여러 이벤트 기록
  audit.log(
    event_type: "access_denied",
    user: "user1@example.com",
    resource: "/api/admin",
    timestamp: now(),
    details: { reason: "permission_denied" }
  )?

  audit.log(
    event_type: "access_denied",
    user: "user2@example.com",
    resource: "/api/admin",
    timestamp: now(),
    details: { reason: "permission_denied" }
  )?

  // 특정 사용자의 실패한 접근 조회
  let logs = audit.query(
    filter: AuditFilter::new()
      .user("user1@example.com")
      .event_type("access_denied")
  )

  assert!(logs.len() >= 1)
}

// Test 5: ACL 관리
test "AccessControlList: 권한 부여 및 확인" {
  let acl = AccessControlList::new()

  // 권한 부여
  acl.grant("user1", "read", "/data/public")?
  acl.grant("user2", "write", "/data/user2")?
  acl.grant("admin", "delete", "/data/sensitive")?

  // 권한 확인
  assert!(acl.check("user1", "read", "/data/public"))
  assert!(!acl.check("user1", "write", "/data/public"))
  assert!(acl.check("user2", "write", "/data/user2"))
  assert!(!acl.check("user2", "delete", "/data/user2"))
}

// Test 6: ACL 권한 거부
test "AccessControlList: 권한 거부 및 철회" {
  let acl = AccessControlList::new()

  acl.grant("user1", "read", "/api/data")?
  acl.grant("user1", "write", "/api/data")?

  // 쓰기 권한 거부
  acl.deny("user1", "write", "/api/data")?

  assert!(acl.check("user1", "read", "/api/data"))
  assert!(!acl.check("user1", "write", "/api/data"))

  // 모든 권한 철회
  acl.revoke("user1", "/api/data")?
  assert!(!acl.check("user1", "read", "/api/data"))
}

// Test 7: 데이터 암호화
test "DataProtector: 암호화 및 복호화" {
  let protector = DataProtector::new()
    .with_encryption(Algorithm::AES256)

  let original = "sensitive_data_12345"
  let encrypted = protector.encrypt(original)?

  // 암호화된 데이터는 원본과 다름
  assert!(encrypted != original)

  // 복호화 후 원본과 동일
  let decrypted = protector.decrypt(encrypted)?
  assert!(decrypted == original)
}

