  // 스위치 추가
  controller.add_switch("s1", OpenFlowVersion::V1_3)?
  controller.add_switch("s2", OpenFlowVersion::V1_3)?
  controller.add_switch("s3", OpenFlowVersion::V1_3)?

  // 호스트 추가
  controller.add_host("h1", "00:00:00:00:00:01", "10.0.0.1")?
  controller.add_host("h2", "00:00:00:00:00:02", "10.0.0.2")?
  controller.add_host("h3", "00:00:00:00:00:03", "10.0.0.3")?

  // 링크 추가
  controller.add_link("s1", "s2", bandwidth: 1000)?
  controller.add_link("s2", "s3", bandwidth: 1000)?
  controller.add_link("s1", "h1", bandwidth: 100)?
  controller.add_link("s2", "h2", bandwidth: 100)?

  // 토폴로지 확인
  let topology = controller.get_topology()
  assert!(topology.switches.len() == 3)
  assert!(topology.hosts.len() == 2)
  assert!(topology.links.len() >= 4)
}

// Test 2: 흐름 규칙 추가
test "SDNController: OpenFlow 흐름 규칙 설정" {
  let controller = SDNController::new()

  controller.add_switch("s1", OpenFlowVersion::V1_3)?

  // 기본 포워딩 규칙
  let flow_id = controller.add_flow(
    switch: "s1",
    match: FlowMatch::new()
      .eth_type(0x0800)  // IPv4
      .ipv4_dst("10.0.0.2"),
    actions: vec![
      FlowAction::SetField(Field::EthDst("00:00:00:00:00:02")),
      FlowAction::Output(port: 2)
    ]
  )?

  assert!(flow_id > 0)
}

// Test 3: QoS 미터 설정
test "SDNController: QoS 메터 구성" {
  let controller = SDNController::new()

  controller.add_switch("s1", OpenFlowVersion::V1_3)?

  // 1Mbps 속도 제한 설정
  controller.add_meter(
    switch: "s1",
    meter_id: 1,
    rate: 1000,      // 1Mbps
    burst_size: 10000
  )?

  // 미터가 설정됨을 확인
}

// Test 4: 최단 경로 계산
test "SDNRouter: Dijkstra 최단 경로 계산" {
  let router = SDNRouter::new()

  // 네트워크 토폴로지 설정
  router.add_switch("s1")
  router.add_switch("s2")
  router.add_switch("s3")
  router.add_host("h1", "10.0.0.1")
  router.add_host("h2", "10.0.0.2")

  router.add_link("s1", "s2", cost: 1)
  router.add_link("s2", "s3", cost: 1)
